  ('locality-c5fb3965-moex-00181', 'locality-c5fb3965', 'locality-c5fb3965-moex-110-3082b5f1', 'sub-locality-c5fb3965-03', NULL, 'single_choice', '關於行政訴訟法中都市計畫審查程序之規定，下列何者錯誤？', '["都市計畫審查訴訟，應於都市計畫發布後1年之不變期間內提起", "被告收受起訴狀繕本後，應於2個月內重新檢討原告請求宣告無效之都市計畫是否合法", "都市計畫審查訴訟，專屬都市計畫區所在地之高等行政法院管轄", "人民認為都市計畫違法或不當，而直接損害其權利者，得提起訴訟，請求宣告該都市計畫無效"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:00+00:00", "source_pdf_sha1": "18fffff4b96c", "answer_pdf_sha1": "f164d0d22d36", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "303", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "戶政"}'::jsonb, NULL),
  ('locality-c5fb3965-moex-00182', 'locality-c5fb3965', 'locality-c5fb3965-moex-110-3082b5f1', 'sub-locality-c5fb3965-03', NULL, 'single_choice', '下列何種情形人民不得主張損失補償？', '["騎樓之所有權人，應開放其騎樓供公眾通行使用", "都市計畫道路用地之所有權人，在依法徵收以前，其用地遭到政府埋設地下設施物", "野生動物保護區土地之所有權人，在依法徵收以前，應以主管機關公告之方法提供野生動物棲 息環境", "水道沿岸之私有土地建造物，經主管機關認為有礙水流者，命所有權人大幅度修改"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:00+00:00", "source_pdf_sha1": "18fffff4b96c", "answer_pdf_sha1": "f164d0d22d36", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "303", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "戶政"}'::jsonb, NULL),
  ('locality-c5fb3965-moex-00183', 'locality-c5fb3965', 'locality-c5fb3965-moex-110-3082b5f1', 'sub-locality-c5fb3965-03', NULL, 'single_choice', '關於國家賠償法公共設施之國家賠償責任規定，下列敘述何者錯誤？', '["該公共設施不以專供公眾使用者為限", "不以故意或過失為要件", "損害須因公共設施設置或管理有欠缺所致", "公共設施須為國家所有"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:00+00:00", "source_pdf_sha1": "18fffff4b96c", "answer_pdf_sha1": "f164d0d22d36", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "303", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "戶政"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00001', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-114-78566e18', 'sub-locality-d0d1b9a2-01', NULL, 'essay', '甲公司 X1 年 12月 31 日將帳面價值$5,000,000之土地，以$9,000,000 出
售給乙公司並立即租回，該出售滿足 IFRS 15 資產銷售之規定。合約租
期3年，每年租金為$2,000,000於每年12月31日支付，並於X3年12月
31 日依過去 24 個月消費者物價指數之增加為基礎，調整最後一期之租
金。於租期屆滿日甲公司需返還土地給乙公司，且甲公司向乙公司保證
租期屆滿日之估計殘值為$8,000,000，甲公司預估租期屆滿日將需就保
證殘值支付$1,000,000。甲公司之增額借款利率為8%，乙公司之租賃隱
含利率為5%，且為甲公司知悉，甲公司採年數合計法提列折舊。X1 年
12 月 31日及 X3年 12 月 31日之消費者物價指數分別為 100及 110。
請回答下列問題：（金額請四捨五入至整數位）
若於銷售日，土地之公允價值為$9,000,000，試作甲公司 X1、X2 及 X3
年底應有之分錄。（20分）
若於銷售日，土地之公允價值為$10,000,000，試作甲公司 X1 年底應
有之分錄。（10分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:05+00:00", "source_pdf_sha1": "58d279cd0639", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "313", "s": "1207", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "中級會計學", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00002', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-114-78566e18', 'sub-locality-d0d1b9a2-01', NULL, 'essay', '下列兩項有關收入之交易分別獨立，請回答相關之會計問題：
甲補習班為慶祝十周年慶，推出 2 年期函授視訊套餐專案，參加此專
案之學員於簽約時先繳交現金$24,000，每月底再繳交$3,000 即可參加
24 個月之函授視訊課程，且亦可再以優惠價$1,000購買全套之應考書
籍。該補習班也有單獨之24 個月之函授視訊課程，訂價為$108,000；
另全套之應考書籍之單獨售價則為$2,000。假設有1位考生於7月1日
支付現金參加此套餐課程，並購買書籍，試作補習班 7 月 1日及7 月
31 日必要之分錄（請四捨五入至整數位）。（10 分）
甲、乙兩公司於 11 月初簽訂 1 年期合約，乙公司以每單位$550 向甲
公司進貨。合約規定，甲公司銷售給乙公司之商品要裝入乙公司生產
之外裝材料中，故甲公司須另以每單位$20 向乙公司購入外裝材料，
該材料之公允價值為$17。此外，甲公司尚需支付商品上架費$1,000 給
乙公司，甲公司不含前述外裝材料之存貨成本為每單位$400。假設11月
份甲公司銷售給乙公司 1,000 單位，同時也向乙公司購買外裝材料
1,200 單位。試問甲公司 11 月份銷售給乙公司 1,000 單位應認列之銷
貨收入為若干？又此批銷貨毛利率為若干（毛利率請四捨五入至小數
點後四位）？（10 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:05+00:00", "source_pdf_sha1": "58d279cd0639", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "313", "s": "1207", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "中級會計學", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00003', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-114-78566e18', 'sub-locality-d0d1b9a2-01', NULL, 'single_choice', '甲公司於X5年度以合約總價$3,000,000承包一項防波堤興建工程，該合約為隨時間逐步滿足之 單一履約義務，甲公司以成本投入法衡量完工程度。已知該合約於 X5、X6 年分別實際投入 $600,000及$900,000之工程成本，X5、X6兩年度分別認列之工程利益均為$150,000。請問有關 此合約，下列敘述何者正確？', '["該合約於X5年底估計完工尚需投入之成本為$2,000,000", "該合約於X6年底估計完工尚需投入之成本為$1,000,000", "該合約於X5年底在建工程之帳面金額為$600,000", "該合約於X6年底在建工程之帳面金額為$1,650,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:05+00:00", "source_pdf_sha1": "58d279cd0639", "answer_pdf_sha1": "c8f8c4a54c39", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "313", "s": "1207", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL)
